#!/usr/bin/env bash
# solver.sh — Solver 决策助手 for 德州扑克策略.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="德州扑克策略"
TOPIC="Solver"

usage() {
  cat <<EOF
solver.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./solver.sh             # interactive
  ./solver.sh --dry-run   # walk through but no file
  ./solver.sh --json      # JSON to stdout
  ./solver.sh --explain   # show backing playbook rules + mental models
  ./solver.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Solver 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 我方有坚果优势(nut advantage) → 则 用极化大注 / overbet(高诈唬含量);**如果仅微弱范围领先(无坚果优势)**, 则用浓缩小注或过牌控池。案例(
  • 如果 想搞懂某个 spot 怎么打 → 则 先用云端站(GTO Wizard)建框架/查预解, 再用本地 solver(Pio/GTO+) 深挖 + node-lo
  • 如果 是高频普适 spot(标准 c-bet 等) → 则 用内化 heuristic 秒过;**把 solver / 复盘 / 选桌的有限带宽集中在非标 spot、疑难手、前 3

相关心智模型:
  • GTO 基线 ⇄ 剥削偏离(equilibrium baseline ⇄ exploitative deviation): 先建一条**不可剥削的均衡基线 (GTO)**,再针对具体对手/人群的可观察漏洞**偏离 (exploit)** 去最大化 EV;GTO 是回得去的**锚点**,不是终点。
  • Range-first(先想范围,再想这手牌): 扑克决策的**原子单位是范围(对手在某节点所有可能持牌的概率分布)**,不是单张牌;高手把对手 put on a *range* 再随每条街的行动收窄。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "我方有坚果优势(nut advantage)"
  "想搞懂某个 spot 怎么打"
  "是高频普适 spot(标准 c-bet 等)"
)
declare -a RULE_ACTIONS=(
  "用极化大注 / overbet(高诈唬含量);**如果仅微弱范围领先(无坚果优势)**, 则用浓缩小注或过牌控池。案例(case):solver 平反了 overbet——只有坚果更多的一方才拿到「大注极化的许可证」,无 nut advantage 却 overbet 是送钱 (evidence: [T06-S009, T04-S031])"
  "先用云端站(GTO Wizard)建框架/查预解, 再用本地 solver(Pio/GTO+) 深挖 + node-lock;**不要一上来背点值**。案例(case):「上手即用云端 → 本地深挖」双层学习栈被几乎所有横评并列推荐;先建直觉框架再上本地 solver (evidence: [T02-S004, T02-S027])"
  "用内化 heuristic 秒过;**把 solver / 复盘 / 选桌的有限带宽集中在非标 spot、疑难手、前 3 大 leak、最弱的桌**(triage 抓主要矛盾)。案例(case):资深人跳过逐 spot 跑解、逐手复盘,只在偏离标准时动用重武器;新手对每个 spot 都想跑解陷入「solver 中毒」(evidence: [T03-S002, T03-S011])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "solver-decision"
fi
